from pydantic import BaseModel
from typing import Optional

class Education(BaseModel):
    degree: str
    institution: str

class ResumeData(BaseModel):
    name: str
    email: Optional[str] = None
    years_experience: Optional[int] = None
    skills: list[str] = []
    education: list[Education] = []

class ResumeParser:
    def __init__(self):
        self.client = OpenAI()

    def parse(self, resume_text: str) -> ResumeData:
        completion = self.client.beta.chat.completions.parse(
            model='gpt-4o',
            messages=[
                {'role': 'system', 'content': 'Extract structured information from this resume.'},
                {'role': 'user',   'content': resume_text}
            ],
            response_format=ResumeData,
            temperature=0.0,
        )
        if completion.choices[0].message.refusal:
            raise ValueError(f'Model refused: {completion.choices[0].message.refusal}')
        return completion.choices[0].message.parsed

    def parse_batch(self, texts: list[str]) -> list[ResumeData]:
        return [self.parse(t) for t in texts]

