import json
import logging
from pydantic import BaseModel

log = logging.getLogger(__name__)

def safe_extract(text: str, schema: type[BaseModel], client, model: str = 'gpt-4o') -> BaseModel | None:
    try:
        completion = client.beta.chat.completions.parse(
            model=model,
            messages=[
                {'role': 'system', 'content': 'Extract structured information.'},
                {'role': 'user', 'content': text}
            ],
            response_format=schema,
            temperature=0.0,
        )
        if completion.choices[0].message.refusal:
            log.warning('Model refused structured output: %s', completion.choices[0].message.refusal)
            return None
        return completion.choices[0].message.parsed
    except Exception as e:
        log.error('Structured extraction failed: %s', e)
        return None
